import { describe, expect, it } from 'vitest';

import {
  PER_LAYER_TENSOR_SUFFIXES,
  RESIDENT_TENSOR_NAMES,
  tensorNamesForLayer,
} from '../src/tensor-names';

describe('tensor-names', () => {
  it('exposes nine per-layer suffixes in canonical order', () => {
    expect(PER_LAYER_TENSOR_SUFFIXES).toHaveLength(9);
    expect(PER_LAYER_TENSOR_SUFFIXES[0]).toBe('attn_norm_weight');
    expect(PER_LAYER_TENSOR_SUFFIXES[8]).toBe('ffn_down_weight');
  });

  it('exposes the three resident names with output_weight last', () => {
    expect(RESIDENT_TENSOR_NAMES).toEqual([
      'token_embd_weight',
      'output_norm_weight',
      'output_weight',
    ]);
  });

  it('builds nine prefixed names for a given layer index', () => {
    const names = tensorNamesForLayer(0);
    expect(names).toHaveLength(9);
    expect(names[0]).toBe('blk_0_attn_norm_weight');
    expect(names[8]).toBe('blk_0_ffn_down_weight');

    const names7 = tensorNamesForLayer(7);
    expect(names7[1]).toBe('blk_7_attn_q_weight');
  });

  it('rejects negative or non-integer layer indices', () => {
    expect(() => tensorNamesForLayer(-1)).toThrow();
    expect(() => tensorNamesForLayer(1.5)).toThrow();
  });
});
